/// Step handler trait for CompanyOnboarding flow
#[async_trait::async_trait]
pub trait CompanyOnboardingStepHandler: Send + Sync {
    /// Handle validate_npwp step
    async fn handle_validate_npwp(
        &self,
        instance: &mut CompanyOnboardingFlowInstance,
    ) -> Result<Option<CompanyOnboardingFlowStep>, FlowError>;

    /// Handle check_code_unique step
    async fn handle_check_code_unique(
        &self,
        instance: &mut CompanyOnboardingFlowInstance,
    ) -> Result<Option<CompanyOnboardingFlowStep>, FlowError>;

    /// Handle write_company step
    async fn handle_write_company(
        &self,
        instance: &mut CompanyOnboardingFlowInstance,
    ) -> Result<Option<CompanyOnboardingFlowStep>, FlowError>;

    /// Handle write_head_office_branch step
    async fn handle_write_head_office_branch(
        &self,
        instance: &mut CompanyOnboardingFlowInstance,
    ) -> Result<Option<CompanyOnboardingFlowStep>, FlowError>;

    /// Handle terminal step onboarded
    async fn handle_onboarded(
        &self,
        instance: &mut CompanyOnboardingFlowInstance,
    ) -> Result<(), FlowError>;

    /// Handle terminal step rejected_invalid_npwp
    async fn handle_rejected_invalid_npwp(
        &self,
        instance: &mut CompanyOnboardingFlowInstance,
    ) -> Result<(), FlowError>;

    /// Handle terminal step rejected_duplicate
    async fn handle_rejected_duplicate(
        &self,
        instance: &mut CompanyOnboardingFlowInstance,
    ) -> Result<(), FlowError>;

}

/// Executor for CompanyOnboarding flow
pub struct CompanyOnboardingFlowExecutor<H: CompanyOnboardingStepHandler> {
    handler: Arc<H>,
}

impl<H: CompanyOnboardingStepHandler> CompanyOnboardingFlowExecutor<H> {
    /// Create a new flow executor
    pub fn new(handler: Arc<H>) -> Self {
        Self { handler }
    }

    /// Start a new flow instance
    pub async fn start(&self, instance_id: impl Into<String>) -> Result<CompanyOnboardingFlowInstance, FlowError> {
        let mut instance = CompanyOnboardingFlowInstance::new(instance_id);
        instance.status = CompanyOnboardingFlowStatus::Running;
        instance.current_step = Some(CompanyOnboardingFlowStep::ValidateNpwp);
        Ok(instance)
    }

    /// Execute the current step
    pub async fn execute_step(&self, instance: &mut CompanyOnboardingFlowInstance) -> Result<(), FlowError> {
        let current_step = match instance.current_step {
            Some(step) => step,
            None => return Err(FlowError::NoCurrentStep),
        };

        let next_step = match current_step {
            CompanyOnboardingFlowStep::ValidateNpwp => {
                self.handler.handle_validate_npwp(instance).await?
            }
            CompanyOnboardingFlowStep::CheckCodeUnique => {
                self.handler.handle_check_code_unique(instance).await?
            }
            CompanyOnboardingFlowStep::WriteCompany => {
                self.handler.handle_write_company(instance).await?
            }
            CompanyOnboardingFlowStep::WriteHeadOfficeBranch => {
                self.handler.handle_write_head_office_branch(instance).await?
            }
            CompanyOnboardingFlowStep::Onboarded => {
                self.handler.handle_onboarded(instance).await?;
                None // Terminal step
            }
            CompanyOnboardingFlowStep::RejectedInvalidNpwp => {
                self.handler.handle_rejected_invalid_npwp(instance).await?;
                None // Terminal step
            }
            CompanyOnboardingFlowStep::RejectedDuplicate => {
                self.handler.handle_rejected_duplicate(instance).await?;
                None // Terminal step
            }
        };

        // Mark current step as completed
        instance.completed_steps.push(current_step);

        // Move to next step
        match next_step {
            Some(next) => {
                instance.current_step = Some(next);
            }
            None => {
                instance.current_step = None;
                instance.status = CompanyOnboardingFlowStatus::Completed;
            }
        }

        instance.updated_at = chrono::Utc::now();
        Ok(())
    }

    /// Run the flow to completion
    pub async fn run(&self, instance: &mut CompanyOnboardingFlowInstance) -> Result<(), FlowError> {
        while !instance.is_complete() && instance.status != CompanyOnboardingFlowStatus::Waiting {
            self.execute_step(instance).await?;
        }
        Ok(())
    }

    /// Cancel the flow
    pub fn cancel(&self, instance: &mut CompanyOnboardingFlowInstance) {
        instance.status = CompanyOnboardingFlowStatus::Cancelled;
        instance.updated_at = chrono::Utc::now();
    }

    /// Mark flow as failed
    pub fn fail(&self, instance: &mut CompanyOnboardingFlowInstance, error: impl Into<String>) {
        instance.status = CompanyOnboardingFlowStatus::Failed;
        instance.error = Some(error.into());
        instance.updated_at = chrono::Utc::now();
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_flow_instance_creation() {
        let instance = CompanyOnboardingFlowInstance::new("test-1");
        assert_eq!(instance.id, "test-1");
        assert_eq!(instance.status, CompanyOnboardingFlowStatus::Pending);
        assert!(!instance.is_complete());
    }

    #[test]
    fn test_flow_context() {
        let mut instance = CompanyOnboardingFlowInstance::new("test-2");
        instance.set_context("key", serde_json::json!("value"));
        let value = instance.get_context("key");
        assert_eq!(value, Some(&serde_json::json!("value")));
    }

    #[test]
    fn test_flow_status_transitions() {
        let mut instance = CompanyOnboardingFlowInstance::new("test-3");
        assert!(!instance.is_running());

        instance.status = CompanyOnboardingFlowStatus::Running;
        assert!(instance.is_running());
        assert!(!instance.is_complete());

        instance.status = CompanyOnboardingFlowStatus::Completed;
        assert!(instance.is_complete());
        assert!(!instance.is_running());
    }
}